	"TOR_WARTE_EXECUTE" NUMBER(*,12) DEFAULT 250 NOT NULL ENABLE, 
	"TOR_RS485_ADRESSE" NUMBER(*,5) DEFAULT 255 NOT NULL ENABLE, 
	"SCHED_RES_ID" NUMBER(*,0) DEFAULT 0 NOT NULL ENABLE
