ALTER TABLE "DIRKSPZM32"."ISI_TOR_CFG" ADD CONSTRAINT "PK_ISI_TOR_CFG" PRIMARY KEY ("TOR_ID_LESEGERAET", "TOR_RS485_ADRESSE")
